window.Chart=class{constructor(t,e){this.ctx=t.getContext('2d');this.data=e.data;this.options=e.options||{};this._chart=this;this.update()}update(){this._draw()}draw(){this._draw()}_draw(){if(!this.data||!this.data.labels)return;const t=this.ctx;this.ctx.clearRect(0,0,this.ctx.canvas.width,this.ctx.canvas.height);const e=this.data.datasets[0]||{};this._renderChart(e)}destroy(){this.ctx.canvas.remove()}_renderChart(t){setTimeout(()=>{switch(this.options.type||'bar'){case'doughnut':this._drawDoughnut(t);break;case'bar':this._drawBar(t);break}},0)}_drawDoughnut(t){const e=this.ctx.canvas.width/2,i=this.ctx.canvas.height/2,n=60;this.ctx.fillStyle='#8b5cf6';this.ctx.beginPath();this.ctx.arc(e,i,n,0,2*Math.PI);this.ctx.fill()}_drawBar(t){const e=this.ctx.canvas.width,i=this.ctx.canvas.height;this.ctx.fillStyle='#6366f1';this.ctx.fillRect(0,0,e/2,i)}};
